member.example:
Bind the AudioSource bypassListenerEffects property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceBypassEffectsBinder _bypassListenerEffects;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassListenerEffects;
    }


Bind the AudioSource bypassListenerEffects property by constructing the binder in code.

    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceBypassListenerEffectsBinder BypassListenerEffects =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _bypassListenerEffects;
    }
